{"code":"from hermes_tools import terminal
import json, subprocess
BASE='QPzQbdDZLasm2vsqeFql0RPsgyg'
MASTER='tblBCgxj19VHYKFE'
SUB='tblMMHFizWL8q0a5'
DATES=['26/4','27/4','30/4','1/5','2/5','3/5']
def lark(cmd):
    r=terminal(cmd, timeout=180)
    if r['exit_code']!=0:
        raise RuntimeError(r['output'])
    return json.loads(r['output'])
master=lark(f'lark-cli base +record-list --as user --base-token {BASE} --table-id {MASTER} --limit 200')
subs=lark(f'lark-cli base +record-list --as user --base-token {BASE} --table-id {SUB} --limit 200')
# map master by name
mf=master['data']['fields']; m={} 
for rid,row in zip(master['data']['record_id_list'], master['data']['data']):
    rm=dict(zip(mf,row)); name=rm.get('Họ và tên')
    if isinstance(name,list) and name: m[name[0]]=rm
sf=subs['data']['field_id_list']; latest={}; dup={}
for row in subs['data']['data']:
    rm=dict(zip(sf,row)); name=rm.get('fldHv7gAJC')
    if isinstance(name,list) and name:
        n=name[0]; dup[n]=dup.get(n,0)+1; latest[n]=list(rm.get('fldvJwefHq') or [])
errors=[]; missing=[]
for n, selected in latest.items():
    if n not in m:
        missing.append(n); continue
    for d in DATES:
        if bool(m[n].get(d)) != (d in selected):
            errors.append({'name':n,'date':d,'dest':bool(m[n].get(d)),'source_expected':d in selected})
print(json.dumps({'source_records':len(subs['data']['record_id_list']),'source_unique_names':len(latest),'dest_records':len(master['data']['record_id_list']),'missing_in_dest':missing,'verify_errors_count':len(errors),'verify_errors_sample':errors[:10],'duplicate_source_names':{k:v for k,v in dup.items() if v>1}}, ensure_ascii=False, indent=2))"}

